1	import { describe, test, expect, beforeEach } from 'bun:test';
2	import { ClaudeAgent } from '../../src/agents/claude/claude-agent';
3	import type { LineParser } from '../../src/agents/agent.interface';
4	import type { ParsedLine } from '../../src/core/types';
5	
6	/**
7	 * Collect all parsed lines from a single JSONL line
8	 */
9	function collectAllParsedLines(
10	  parser: LineParser,
11	  line: string,
12	  maxIterations = 100
13	): ParsedLine[] {
14	  const results: ParsedLine[] = [];
15	  let parsed = parser.parse(line);
16	  let iterations = 0;
17	
18	  while (parsed && iterations < maxIterations) {
19	    results.push(parsed);
20	    parsed = parser.parse(line);
21	    iterations++;
22	  }
23	
24	  if (iterations >= maxIterations) {
25	    throw new Error('Infinite loop detected');
26	  }
27	  return results;
28	}
29	
30	describe('ClaudeAgent parser taskDescription', () => {
31	  let parser: LineParser;
32	
