26	/** JSONL event type for Claude /rename command */
27	const CUSTOM_TITLE_TYPE = 'custom-title';
28	
29	/**
30	 * Claude Code Session Finder
31	 * 目錄結構: ~/.claude/projects/{encoded-path}/{UUID}.jsonl
32	 */
33	class ClaudeSessionFinder implements SessionFinder {
34	  private baseDir: string;
35	
36	  constructor() {
37	    this.baseDir = join(homedir(), '.claude', 'projects');
38	  }
39	
40	  getBaseDir(): string {
41	    return this.baseDir;
42	  }
43	
44	  /**
45	   * 收集所有主 session 檔案（共用邏輯）
46	   * 回傳按 mtime 降序排列的 SessionListItem[]
47	   */
48	  private async _collectMainSessions(options: {
49	    project?: string;
50	  }): Promise<SessionListItem[]> {
51	    const glob = new Glob('**/*.jsonl');
52	    const files: SessionListItem[] = [];
53	
54	    const uuidPattern =
55	      /^([0-9a-f]{8})-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}\.jsonl$/i;
56	
57	    for await (const file of glob.scan({
58	      cwd: this.baseDir,
59	      absolute: true,
60	    })) {
61	      const filename = file.split('/').pop() || '';
62	
63	      // 排除 agent-* 開頭的檔案
64	      if (filename.startsWith('agent-')) continue;
65	
66	      // 只匹配 UUID 格式的檔案名
67	      const match = uuidPattern.exec(filename);
68	      if (!match) continue;
69	
70	      // 如果有 project filter，做模糊比對
71	      if (options.project) {
72	        const pattern = options.project.toLowerCase();
73	        if (!file.toLowerCase().includes(pattern)) continue;
74	      }
75	
76	      try {
77	        const stats = await stat(file);
78	        // 從路徑提取專案名（父目錄名）
79	        const parts = file.split('/');
80	        const projectIdx = parts.indexOf(filename) - 1;
81	        const project = projectIdx >= 0 ? parts[projectIdx] : undefined;
82	
83	        files.push({
84	          path: file,
85	          mtime: stats.mtime,
86	          agentType: 'claude',
87	          shortId: match[1]!,
88	          project,
89	        });
90	      } catch {
91	        // 忽略無法讀取的檔案
92	      }
93	    }
94	
95	    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
96	    return files;
97	  }
98	
99	  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
100	    const files = await this._collectMainSessions(options);
101	    if (files.length === 0) return null;
102	
103	    const latest = files[0]!;
104	    const customTitle = await readCustomTitle(latest.path);
105	    return {
106	      path: latest.path,
107	      mtime: latest.mtime,
108	      agentType: 'claude',
109	      ...(customTitle ? { customTitle } : {}),
110	    };
111	  }
112	
113	  async listSessions(options: {
114	    project?: string;
115	    limit?: number;
116	  }): Promise<SessionListItem[]> {
117	    const files = await this._collectMainSessions(options);
118	    const limit = options.limit ?? 20;
119	    const sliced = files.slice(0, limit);
120	
121	    // Enrich with tail-read metadata (parallel I/O, 8KB per file)
122	    await Promise.all(
123	      sliced.map(async (item) => {
124	        const [lastTs, title, cwd] = await Promise.all([
125	          readLastTimestampFromJSONL(item.path),
126	          readCustomTitleFromTail(item.path),
127	          readCwdFromHead(item.path),
128	        ]);
129	        item.lastActivityTime = lastTs ?? undefined;
130	        if (title) item.customTitle = title;
131	        if (cwd) item.project = cwd;
132	      })
133	    );
134	
135	    // Re-sort by lastActivityTime (more accurate than mtime)
136	    sliced.sort((a, b) => {
137	      const ta = (a.lastActivityTime ?? a.mtime).getTime();
138	      const tb = (b.lastActivityTime ?? b.mtime).getTime();
139	      return tb - ta;
140	    });
141	
142	    return sliced;
143	  }
144	
145	  /**
146	   * 找到 subagent 檔案
147	   * 新結構: {sessionId}/subagents/agent-{7位hex}.jsonl
148	   * @param options.subagentId - 指定的 subagent ID，不提供則找最新的
149	   */
150	  async findSubagent(options: {
151	    project?: string;
152	    subagentId?: string;
153	  }): Promise<SessionFile | null> {
154	    const { project, subagentId } = options;
155	
156	    // 決定 glob pattern（新結構：{UUID}/subagents/ 目錄下）
157	    const pattern = subagentId
158	      ? `**/*/subagents/agent-${subagentId}.jsonl`
159	      : '**/*/subagents/agent-*.jsonl';
160	
161	    const glob = new Glob(pattern);
162	    const files: { path: string; mtime: Date }[] = [];
163	
164	    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
165	      const filename = file.split('/').pop() || '';
166	
167	      // 驗證 subagent 檔名格式: agent-{7~40位十六進制}.jsonl
168	      const subagentPattern = /^agent-[0-9a-f]{7,40}\.jsonl$/i;
169	      if (!subagentPattern.test(filename)) continue;
170	
171	      // project filter
172	      if (project && !file.toLowerCase().includes(project.toLowerCase())) {
173	        continue;
174	      }
175	
176	      try {
177	        const stats = await stat(file);
178	        files.push({ path: file, mtime: stats.mtime });
179	      } catch {
180	        // 忽略無法讀取的檔案
181	      }
182	    }
183	
184	    if (files.length === 0) return null;
185	
186	    // 按修改時間排序，取最新的
187	    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
188	    const latest = files[0];
189	    if (!latest) return null;
190	
191	    return {
192	      path: latest.path,
193	      mtime: latest.mtime,
194	      agentType: 'claude',
195	    };
196	  }
197	
198	  /**
199	   * 依 session ID 查找 session 檔案
200	   * 支援主 session（UUID）和 subagent（7位hex）
201	   * 當指定 subagent ID 時，會同時返回主 session 和 subagent
202	   */
203	  async findBySessionId(
204	    sessionId: string,
205	    options: { project?: string }
206	  ): Promise<SessionFile | ClaudeSessionResult | null> {
207	    const idType = this.detectIdType(sessionId);
208	
209	    // 如果是主 session UUID 或未知類型，先嘗試找主 session
210	    if (idType === 'main' || idType === 'unknown') {
211	      const mainResult = await this.findMainBySessionId(sessionId, options);
212	      if (mainResult) return mainResult;
213	    }
214	
215	    // 如果是 subagent ID 或未知類型（且主 session 沒找到），嘗試找 subagent
216	    if (idType === 'subagent' || idType === 'unknown') {
217	      const subagentResult = await this.findSubagentBySessionId(
218	        sessionId,
219	        options
220	      );
221	      if (subagentResult) {
222	        // 反推主 session
223	        const mainPath = this.getMainSessionFromSubagent(subagentResult.path);
224	        if (mainPath) {
225	          try {
226	            const [mainStats, mainTitle] = await Promise.all([
227	              stat(mainPath),
228	              readCustomTitle(mainPath),
229	            ]);
230	            return {
231	              main: {
232	                path: mainPath,
233	                mtime: mainStats.mtime,
234	                agentType: 'claude',
