236	              },
237	              subagent: subagentResult,
238	            };
239	          } catch {
240	            // 主 session 不存在，只返回 subagent
241	            return subagentResult;
242	          }
243	        }
244	        return subagentResult;
245	      }
246	    }
247	
248	    return null;
249	  }
250	
251	  /**
252	   * 判斷 ID 類型
253	   */
254	  private detectIdType(id: string): 'main' | 'subagent' | 'unknown' {
255	    // 完整 UUID 格式
256	    const uuidPattern =
257	      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
258	    // Subagent 格式：agent-{7hex} 或純 {7hex}
