export async function scanForNewSubagents(
  subagentsDir: string,
  knownAgentIds: Set<string>
): Promise<string[]> {
  const newAgentIds: string[] = [];
  try {
    const glob = new Glob('agent-*.jsonl');
    for await (const file of glob.scan({ cwd: subagentsDir })) {
      // Defensive: skip anything under a subdirectory (e.g. workflows/wf_*/agent-*.jsonl).
      if (file.includes('/')) continue;

      const match = file.match(/^agent-([0-9a-f]{7,40})\.jsonl$/i);
      if (match && match[1]) {
        const agentId = match[1];
        if (!knownAgentIds.has(agentId)) newAgentIds.push(agentId);
      }
    }
  } catch {
    // ignore
  }
  return newAgentIds;
}
```

Single-line addition: `if (file.includes('/')) continue;`. The `fs.watch` path is naturally guarded (filename for `workflows/` events is `'workflows'`, which fails the agent regex).

